import{_ as e,a,b as d,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as l,o as i,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"S3 चैनल जोड़ना","description":"","frontmatter":{},"headers":[],"relativePath":"hi/upload/s3.md","filePath":"hi/upload/s3.md","lastUpdated":1781962217000}'),c={name:"hi/upload/s3.md"};function r(p,t,h,u,m,b){return i(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="s3-चैनल-जोड़ना" tabindex="-1">S3 चैनल जोड़ना <a class="header-anchor" href="#s3-चैनल-जोड़ना" aria-label="Permalink to &quot;S3 चैनल जोड़ना&quot;">​</a></h1><h2 id="कब-सबसे-सही-है" tabindex="-1">कब सबसे सही है <a class="header-anchor" href="#कब-सबसे-सही-है" aria-label="Permalink to &quot;कब सबसे सही है&quot;">​</a></h2><p>S3 channel का उपयोग तब करें जब:</p><ul><li>आप Cloudflare R2, Backblaze B2, MinIO, AWS S3 या किसी अन्य compatible provider जैसी S3-compatible object storage service जोड़ना चाहते हैं।</li><li>आप standard S3 configuration model पसंद करते हैं: <code>Endpoint</code>, Access Key और Secret Key।</li><li>आप native Cloudflare R2 binding channel इस्तेमाल नहीं करना चाहते, या आपका storage provider Cloudflare R2 नहीं है।</li></ul><h2 id="शुरू-करने-से-पहले-क्या-चाहिए" tabindex="-1">शुरू करने से पहले क्या चाहिए <a class="header-anchor" href="#शुरू-करने-से-पहले-क्या-चाहिए" aria-label="Permalink to &quot;शुरू करने से पहले क्या चाहिए&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ज़रूरत</th><th>उपयोग</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>object storage service का S3 API endpoint।</td></tr><tr><td>Bucket name</td><td>वह bucket जहाँ files रखी जाएँगी।</td></tr><tr><td>Region</td><td>storage region। Cloudflare R2 के लिए आम तौर पर <code>auto</code>।</td></tr><tr><td>Access Key ID</td><td>S3 access key ID।</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key।</td></tr><tr><td>CDN domain</td><td>file access के लिए optional custom domain।</td></tr></tbody></table><p>Cloudflare R2 को S3 API से इस्तेमाल करने का उदाहरण:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="कहाँ-जोड़ें" tabindex="-1">कहाँ जोड़ें <a class="header-anchor" href="#कहाँ-जोड़ें" aria-label="Permalink to &quot;कहाँ जोड़ें&quot;">​</a></h2><ol><li>System Settings खोलें।</li><li>Upload Settings पर जाएँ।</li><li>ऊपर दाएँ कोने में Add Channel पर क्लिक करें।</li><li><code>S3</code> चुनें।</li></ol><h2 id="फ़ील्ड-संदर्भ" tabindex="-1">फ़ील्ड संदर्भ <a class="header-anchor" href="#फ़ील्ड-संदर्भ" aria-label="Permalink to &quot;फ़ील्ड संदर्भ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>क्या करता है</th><th>आवश्यक</th></tr></thead><tbody><tr><td>Channel name</td><td>S3 channel का आसान नाम, जैसे <code>s3test</code> या <code>R2-S3</code>।</td><td>हाँ</td></tr><tr><td>Enable channel</td><td>यह channel upload selection में शामिल होगा या नहीं।</td><td>सुझाया गया</td></tr><tr><td>Endpoint</td><td><code>https://</code> सहित पूरा S3 service endpoint।</td><td>हाँ</td></tr><tr><td>Custom CDN domain</td><td>optional। set होने पर generated file links इस domain को prefer करते हैं।</td><td>नहीं</td></tr><tr><td>Bucket name</td><td>bucket name, जैसे <code>s3test</code> या <code>img-r2</code>।</td><td>हाँ</td></tr><tr><td>Bucket region</td><td>region। Cloudflare R2 के लिए आम तौर पर <code>auto</code>।</td><td>हाँ</td></tr><tr><td>Access Key ID</td><td>S3 access key ID।</td><td>हाँ</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key।</td><td>हाँ</td></tr><tr><td>Path-style access</td><td>compatibility switch। default off। कुछ MinIO, OpenList या self-hosted S3 services को इसकी ज़रूरत हो सकती है।</td><td>नहीं</td></tr><tr><td>Quota limit</td><td>capacity के आधार पर यह S3 channel upload selection में शामिल होगा या नहीं।</td><td>नहीं</td></tr><tr><td>Capacity limit</td><td>quota limit enable होने के बाद ज़रूरी, जैसे <code>10 GB</code>।</td><td>quota limit चालू हो तो आवश्यक</td></tr><tr><td>Threshold</td><td>usage इस percentage तक पहुँचने पर writing रोकता है, जैसे <code>90%</code>।</td><td>quota limit चालू हो तो आवश्यक</td></tr><tr><td>Remark</td><td>आपकी maintenance notes।</td><td>नहीं</td></tr></tbody></table><h2 id="cloudflare-r2-s3-api-keys-बनाएँ" tabindex="-1">Cloudflare R2 S3 API keys बनाएँ <a class="header-anchor" href="#cloudflare-r2-s3-api-keys-बनाएँ" aria-label="Permalink to &quot;Cloudflare R2 S3 API keys बनाएँ&quot;">​</a></h2><ol><li>Cloudflare Dashboard खोलें।</li><li><code>R2 Object Storage</code> पर जाएँ।</li><li><code>Manage R2 API Tokens</code> या API token management entry ढूँढें।</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>target bucket access कर सकने वाला R2 API token बनाएँ।</li></ol><p><img src="`+e+'" alt="Account API token बनाएँ" loading="lazy"></p><ol start="5"><li>generated <code>Access Key ID</code> और <code>Secret Access Key</code> copy करें।</li></ol><p><img src="'+a+'" alt="Token values copy करें" loading="lazy"></p><ol start="6"><li>R2 bucket page पर लौटें और bucket name confirm करें।</li><li>account का S3 API endpoint note करें। आम तौर पर यह ऐसा दिखता है:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings खोलें।</li><li>Add Channel पर क्लिक करें।</li><li><code>S3</code> चुनें।</li><li>पहचानने लायक channel name डालें, जैसे <code>s3test</code>।</li><li><code>Endpoint</code> में S3 API endpoint डालें।</li><li>custom CDN उपयोग करते हैं तो <code>Custom CDN domain</code> में डालें; नहीं तो खाली छोड़ें।</li><li>bucket name डालें।</li><li>region डालें। Cloudflare R2 example के लिए <code>auto</code> उपयोग करें।</li><li>Access Key ID और Secret Access Key डालें।</li><li>जब तक provider स्पष्ट रूप से न कहे, path-style access off रखें।</li><li>capacity control चाहिए तो quota limit enable करके capacity limit और threshold डालें।</li><li>Save पर क्लिक करें।</li></ol><p><img src="'+d+'" alt="S3 configuration जोड़ें" loading="lazy"></p><h2 id="कैसे-जाँचें" tabindex="-1">कैसे जाँचें <a class="header-anchor" href="#कैसे-जाँचें" aria-label="Permalink to &quot;कैसे जाँचें&quot;">​</a></h2><table tabindex="0"><thead><tr><th>जाँच</th><th>कैसे verify करें</th></tr></thead><tbody><tr><td>Channel card दिखता है</td><td>save करने के बाद Upload Settings page में S3 channel card दिखना चाहिए।</td></tr><tr><td>Channel enabled है</td><td>card के ऊपर दाएँ switch को on रहना चाहिए।</td></tr><tr><td>मुख्य fields save हैं</td><td>detail view में Endpoint, Bucket, Region, path-style access और related fields दिखने चाहिए।</td></tr><tr><td>Upload काम करता है</td><td>test image upload करें और object target bucket में दिखाई दे।</td></tr><tr><td>Link खुलता है</td><td>upload के बाद लौटाया गया image link normally खुलना चाहिए।</td></tr><tr><td>Capacity display काम करता है</td><td>quota limit enabled हो तो card used capacity और configured limit दिखाए।</td></tr></tbody></table><p>S3 capacity statistics ImgBed के local file records से calculate होती हैं, provider bucket को real time query करके नहीं। S3 configuration save होने के बाद system current D1 records से quota ledger recalculate करता है।</p><p><img src="'+s+`" alt="Quota query successful" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="क्या-path-style-access-enable-करना-चाहिए" tabindex="-1">क्या path-style access enable करना चाहिए? <a class="header-anchor" href="#क्या-path-style-access-enable-करना-चाहिए" aria-label="Permalink to &quot;क्या path-style access enable करना चाहिए?&quot;">​</a></h3><p>आम तौर पर नहीं।</p><p>इसे केवल तब enable करें जब आपका S3-compatible provider virtual-hosted-style URLs support नहीं करता, या provider documentation स्पष्ट रूप से path-style access मांगता है। कुछ MinIO, self-hosted S3 और OpenList-compatible endpoints में इसकी ज़रूरत हो सकती है।</p><h3 id="cdn-domain-किसलिए-है" tabindex="-1">CDN domain किसलिए है? <a class="header-anchor" href="#cdn-domain-किसलिए-है" aria-label="Permalink to &quot;CDN domain किसलिए है?&quot;">​</a></h3><p>अगर bucket के आगे CDN या custom access domain है, तो यहाँ डालें।</p><p>configure होने के बाद generated file links इस domain को prefer करेंगे। CDN उपयोग नहीं करते तो खाली छोड़ें।</p><h3 id="upload-क्यों-fail-होता-है" tabindex="-1">Upload क्यों fail होता है? <a class="header-anchor" href="#upload-क्यों-fail-होता-है" aria-label="Permalink to &quot;Upload क्यों fail होता है?&quot;">​</a></h3><p>पहले ये बातें जाँचें:</p><ol><li>Endpoint पूरा <code>https://</code> URL है।</li><li>bucket name सही है।</li><li>Region provider requirement से match करता है।</li><li>Access Key ID और Secret Access Key पूरी तरह copy किए गए हैं।</li><li>key के पास target bucket में write permission है।</li><li>provider path-style access नहीं मांगता, या अगर मांगता है तो path-style access enable है।</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S3 Endpoint, Bucket, Region, Access Key और Secret Key तैयार करें</span></span>
<span class="line"><span>-&gt; Upload Settings खोलें</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; S3 चुनें</span></span>
<span class="line"><span>-&gt; Endpoint / Bucket / Region / Access Key / Secret Key डालें</span></span>
<span class="line"><span>-&gt; ज़रूरत हो तो CDN domain डालें</span></span>
<span class="line"><span>-&gt; default रूप से path-style access off रखें</span></span>
<span class="line"><span>-&gt; ज़रूरत हो तो quota limit enable करें</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; test image upload करके result देखें</span></span></code></pre></div>`,40)])])}const f=l(c,[["render",r]]);export{k as __pageData,f as default};
